"use client";

import { useQuery } from "@tanstack/react-query";
import { useParams } from "next/navigation";

import { getPlayer } from "../../../lib/api";

export default function PlayerDetailPage() {
  const params = useParams<{ id: string }>();
  const playerId = Number(params?.id);

  const { data, isLoading, error } = useQuery({
    queryKey: ["player", playerId],
    queryFn: () => getPlayer(playerId),
    enabled: Number.isFinite(playerId)
  });

  if (isLoading) {
    return <p className="text-slate">Loading player profile...</p>;
  }

  if (error || !data) {
    return <p className="text-red-500">Player not found.</p>;
  }

  return (
    <section className="grid gap-6">
      <div>
        <p className="text-xs uppercase tracking-[0.3em] text-slate">Player Profile</p>
        <h2 className="text-3xl font-semibold mt-2">{data.name}</h2>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        <div className="rounded-2xl bg-white/80 p-4 border border-white">
          <p className="text-sm text-slate">Roster info</p>
          <div className="mt-3 text-sm">
            <p>Number: {data.number ?? "-"}</p>
            <p>Position: {data.position ?? "-"}</p>
          </div>
        </div>
        <div className="rounded-2xl bg-white/80 p-4 border border-white">
          <p className="text-sm text-slate">Performance</p>
          <p className="mt-3 text-sm text-slate">Player match stats will appear here once ingested.</p>
        </div>
      </div>
    </section>
  );
}
